/* 
 * FIX PARA ERROR 414 - REQUEST-URI TOO LARGE
 * Este nodo usa la librería AWS-SDK para enviar el email mediante POST BODY
 * evitando el límite de URL que tiene el nodo nativo de n8n v1.
 */

const AWS = require('aws-sdk');

// 1. CONFIGURA TUS CREDENCIALES AQUÍ
// NOTA: Es importante que las pongas aquí porque el nodo de código no lee 
// las credenciales del almacén de n8n automáticamente.
AWS.config.update({
  accessKeyId: 'AKIA5DQJYVAKYDIJLBHP', // Reemplaza con tu Key
  secretAccessKey: 'REEMPLAZAR_CON_TU_SECRET_KEY', 
  region: 'us-east-1' // Asegúrate que sea la región correcta
});

const ses = new AWS.SES();

// 2. EXTRAER DATOS DEL WEBHOOK
// Recuperamos los datos que envía el CRM (subject, email, html)
const body = $node["Webhook"].getMatchingItem().json.body;

const params = {
  Destination: {
    ToAddresses: [body.email]
  },
  Message: {
    Body: {
      Html: {
        Charset: "UTF-8",
        Data: body.html
      }
    },
    Subject: {
      Charset: "UTF-8",
      Data: body.subject
    }
  },
  Source: "bienesraices@aliminspa.cl", // Debe ser un remitente verificado en tu AWS SES
};

try {
  const result = await ses.sendEmail(params).promise();
  return { 
    status: 'success', 
    messageId: result.MessageId, 
    email: body.email 
  };
} catch (error) {
  return { 
    status: 'error', 
    message: error.message, 
    email: body.email 
  };
}
